final class AuthManager: ObservableObject {
    @Published var isAuthenticated: Bool {
        didSet {
            UserDefaults.standard.set(isAuthenticated, forKey: Keys.isAuthenticated)
        }
    }

    @Published var biometricType: LABiometryType = .none
    @Published var authErrorMessage: String?
    @Published var isAuthenticating = false

    private enum Keys {
        static let isAuthenticated = "isAuthenticated"
    }

    init() {
        self.isAuthenticated = UserDefaults.standard.bool(forKey: Keys.isAuthenticated)
        self.biometricType = currentBiometricType()
    }

    func refreshBiometricType() {
        biometricType = currentBiometricType()
    }

    func logout() {
        isAuthenticated = false
        authErrorMessage = nil
    }

    func loginWithPassword(username: String, password: String) -> Bool {
        let success = !username.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty &&
                      !password.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty
        if success {
            isAuthenticated = true
            authErrorMessage = nil
        } else {
            authErrorMessage = "Please enter a valid username and password."
        }
        return success
    }

    func authenticateWithBiometrics(completion: ((Bool) -> Void)? = nil) {
        isAuthenticating = true
        authErrorMessage = nil

        let context = LAContext()
        context.localizedCancelTitle = "Use Password"
        context.localizedFallbackTitle = "Enter Password"

        var error: NSError?
        let policy: LAPolicy = .deviceOwnerAuthenticationWithBiometrics

        if context.canEvaluatePolicy(policy, error: &error) {
            biometricType = context.biometryType
            let reason = biometricReason(for: context.biometryType)

            context.evaluatePolicy(policy, localizedReason: reason) { [weak self] success, evalError in
                DispatchQueue.main.async {
                    guard let self else { return }
                    self.isAuthenticating = false

                    if success {
                        self.isAuthenticated = true
                        self.authErrorMessage = nil
                        completion?(true)
                    } else {
                        self.isAuthenticated = false
                        self.authErrorMessage = self.userFriendlyMessage(for: evalError)
                        completion?(false)
                    }
                }
            }
        } else {
            DispatchQueue.main.async {
                self.isAuthenticating = false
                self.biometricType = context.biometryType
                self.authErrorMessage = self.userFriendlyMessage(for: error)
                completion?(false)
            }
        }
    }

    private func currentBiometricType() -> LABiometryType {
        let context = LAContext()
        var error: NSError?
        _ = context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error)
        return context.biometryType
    }

    private func biometricReason(for type: LABiometryType) -> String {
        switch type {
        case .faceID:
            return "Use Face ID to securely sign in."
        case .touchID:
            return "Use Touch ID to securely sign in."
        default:
            return "Use biometrics to securely sign in."
        }
    }

    private func userFriendlyMessage(for error: Error?) -> String {
        guard let laError = error as? LAError else {
            return "Authentication failed. Please try again or enter your password."
        }

        switch laError.code {
        case .authenticationFailed:
            return "We couldn’t verify your identity. Please try again or enter your password."
        case .userCancel:
            return "Authentication was canceled. You can try again or enter your password."
        case .userFallback:
            return "Please enter your password to continue."
        case .biometryNotAvailable:
            return "Biometric authentication is not available on this device. Please enter your password."
        case .biometryNotEnrolled:
            return "No Face ID or Touch ID is set up. Please enter your password."
        case .biometryLockout:
            return "Biometrics are temporarily locked. Please enter your password to continue."
        case .systemCancel:
            return "Authentication was interrupted. Please try again."
        case .passcodeNotSet:
            return "A device passcode is required to use biometrics. Please enter your password."
        default:
            return "Authentication failed. Please try again or enter your password."
        }
    }
