struct LoginView: View {
    @EnvironmentObject private var authManager: AuthManager
    @State private var username = ""
    @State private var password = ""
    @State private var attemptedBiometricOnAppear = false

    var body: some View {
        NavigationView {
            VStack(spacing: 20) {
                Spacer()

                VStack(spacing: 8) {
                    Text("Welcome Back")
                        .font(.largeTitle.bold())

                    Text("Sign in with biometrics or your password")
                        .foregroundColor(.secondary)
                }

                VStack(spacing: 16) {
                    TextField("Username", text: $username)
                        .textContentType(.username)
                        .textInputAutocapitalization(.never)
                        .autocorrectionDisabled(true)
                        .padding()
                        .background(Color(.secondarySystemBackground))
                        .cornerRadius(12)

                    SecureField("Password", text: $password)
                        .textContentType(.password)
                        .padding()
                        .background(Color(.secondarySystemBackground))
                        .cornerRadius(12)
                }

                if let error = authManager.authErrorMessage {
                    Text(error)
                        .font(.footnote)
                        .foregroundColor(.red)
                        .multilineTextAlignment(.center)
                        .padding(.horizontal)
                }

                Button {
                    _ = authManager.loginWithPassword(username: username, password: password)
                } label: {
                    Text("Sign In")
                        .frame(maxWidth: .infinity)
                        .padding()
                        .background(Color.blue)
                        .foregroundColor(.white)
                        .cornerRadius(12)
                }

                if authManager.biometricType != .none {
                    Button {
                        authManager.authenticateWithBiometrics()
                    } label: {
                        HStack {
                            Image(systemName: authManager.biometricType == .faceID ? "faceid" : "touchid")
                            Text(authManager.biometricType == .faceID ? "Try Face ID Again" : "Try Touch ID Again")
                        }
                        .frame(maxWidth: .infinity)
                        .padding()
                        .background(Color(.tertiarySystemBackground))
                        .foregroundColor(.primary)
                        .cornerRadius(12)
                    }
                    .disabled(authManager.isAuthenticating)
                }

                Spacer()
            }
            .padding()
            .navigationBarHidden(true)
        }
        .onAppear {
            guard !attemptedBiometricOnAppear else { return }
            attemptedBiometricOnAppear = true
            if authManager.biometricType != .none {
                authManager.authenticateWithBiometrics()
            }
        }
    }
}

